以下是基于ARM架构的Linux系统中，针对TLV320AIC31声卡芯片的设备树配置示例：

```
sound {
    compatible = "ti,tlv320aic31";
    model = "TLV320AIC31";
    #sound-dai-cells = <0>;

    codec@0 {
        #sound-dai-cells = <0>;
        compatible = "ti,tlv320aic31";
        reg = <0>;
        clocks = <&clks 22>, <&clks 23>, <&clks 24>;
        clock-names = "pll", "mclk", "bclk";
        micbias-resistor-kohms = <2>;
        micpga-gain = <48>;
        micpga-bias = <1>;
        micpga-step-size-db = <2>;
        micpga-num-steps = <8>;
        micpga-mute-gpio = <&gpio1 20 GPIO_ACTIVE_LOW>;
        mic-det-gpio = <&gpio1 23 GPIO_ACTIVE_HIGH>;
        headset-det-gpio = <&gpio1 27 GPIO_ACTIVE_HIGH>;
        hp-det-gpio = <&gpio1 29 GPIO_ACTIVE_HIGH>;
        mic-det-debounce-ms = <50>;
        headset-det-debounce-ms = <50>;
        hp-det-debounce-ms = <50>;
        ti,aalc-container-dai-link {
            name = "coefficient-data";
            sai-controller = <&sai1>;
            sai-dma-engine = <&xvdmad0>;
            sai-source-port = <3>;
            sai-dai-port = <2>;
            sai-format = "i2s";
            sai-clock = "mclk";
            sai-bitclk = <48000>;
            sai-word-size = <16>;
            sai-word-length = <16>;
            sai-lrck-polarity = <0>;
            sai-bitclk-polarity = <0>;
            sai-tdm-slots = <2>;
            sai-tdm-slot-width = <16>;
        };
    };
};
```

上述配置中，`sound`节点表示将要配置一个声卡设备，属性`compatible`指定了声卡类型为TLV320AIC31，`model`指定了设备型号为"TLV320AIC31"。

`codec@0`节点表示配置声卡芯片，`compatible`属性同样指定设备类型为TLV320AIC31，并指定其在设备数中的唯一标识符为`0`。`reg`属性指定设备在设备树中的节点地址。`clocks`和`clock-names`分别指定声卡芯片需要使用的时钟源，以及这些时钟源在设备树中的名称。

其余的属性分别代表着声卡芯片对象的各种功能、参数、IO口及其配置等。在实际的设备树中，这些属性还可以根据需要进行扩展和添加。

以下是基于ARM架构的Linux系统中，针对TLV320AIC3101声卡芯片的设备树配置示例：

```
sound {
    compatible = "ti,tlv320aic3101";
    model = "TLV320AIC3101";
    #sound-dai-cells = <0>;

    codec@0 {
        #sound-dai-cells = <0>;
        compatible = "ti,tlv320aic3101";
        reg = <0>;
        clock-frequency = <12288000>;

        /* Input configuration */
        micpga {
            micpga-gain = <30>;
            micpga-bias = <3>;
        };
        micbias {
            micbias-resistor-kohms = <2>;
        };
        dapm {
            pinctrl-0 = <&dapm_mic_in>;
            pinctrl-names = "default";
            dapm_mic_in: micinput {
                compatible = "ti,audio-routing";
                ti,audio-routing = "Mic Jack", "MICBIAS1R",
                                   "MICBIAS1R", "Mic Bias";
            };
        };

        /* Output configuration */
        hpdrivers {
            output-drive-capacity-mw = <560>;
            dds-playback-volume;
            /* The amplifier needs the DACLRC polarity inverted */
            ti,dac-polarity-inversion;
        };
        dapm {
            pinctrl-0 = <&dapm_hp>;
            pinctrl-names = "default";
            dapm_hp: hpl-output {
                /* HPL routing - enabled on boot */
                compatible = "ti,audio-routing";
                ti,audio-routing = "HPL", "LOUTL";
                ti,audio-routing = "HPR", "LOUTR";
            };
        };

        /* ASoC CPU DAI configuration */
        cpu_dai: cpu {
            sound-dai = <&i2s>;
            bitclock-slave = <1>;
            frame-slave = <1>;
        };

        /* ASoC CODEC DAI configuration */
        codec_dai: codec {
            sound-dai = <&aic3101_tdm>;
            bitclock-master = <1>;
            frame-master = <1>;
            dai-format = "i2s";
            codec,name = "tlv320aic3101";
            codec,dac-digital-volume;
            status = "okay";
            tdm-slot-num-masters = <1>;
            tdm-slot-num-slaves = <1>;
            tdm-slot-width = <16>;
        };

        /* TDM link configuration */
        aic3101_tdm: tdm-codec {
            #sound-dai-cells = <0>;
            status = "okay";
            format = "i2s";
            tdm-slots = <2>;
            tdm-slot-width = <16>;
        };
    };
};
```

上述配置中，`sound`节点表示将要配置一个声卡设备，属性`compatible`指定了设备类型为TLV320AIC3101，`model`指定了设备型号为"TLV320AIC3101"。

`codec@0`节点表示配置声卡芯片，`compatible`属性同样指定设备类型为TLV320AIC3101，并指定其在设备数中的唯一标识符为`0`。`reg`属性指定设备在设备树中的节点地址，`clock-frequency`属性指定时钟频率为12.288MHz。

在输入和输出的配置中，属性`micpga-gain`、`micpga-bias`、`micbias-resistor-kohms`等分别代表着MIC预放大器增益、偏置电压、MIC偏置电阻等参数配置。

在CPU DAI和CODEC DAI配置中，CPU DAI节点表示配置通信接口，这里使用i2s总线；CODEC DAI节点表示配置声卡芯片的数字音频接口，说明了使用i2s协议，还对数字音量进行了配置和编码格式等其它参数设置。

最后，TDM link配置中指定了TDM数据的宽度、TDM的时隙等属性。其中，`tdm-codec`属性用于定义TDM编解码器节点，`format`属性指定了i2s格式。在实际的设备树中，这些属性还可以根据需要进行扩展和添加。

